1	const PROCESSING_FEE = 5;
2	const FIRST_QUOTE_SURCHARGE_RATE = 0.1;
3	const BASE_PRICE_BY_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	};
9	
10	type QuoteStep = { op: "quote"; items: Array<{ type: string }> };
11	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
12	
13	const quotePremium = (items: Array<{ type: string }>): number => {
14	  const basePrice = items.reduce((sum, item) => sum + BASE_PRICE_BY_TYPE[item.type], 0);
15	  const firstQuoteSurcharge = basePrice * FIRST_QUOTE_SURCHARGE_RATE;
16	  return basePrice + firstQuoteSurcharge + PROCESSING_FEE;
17	};
18	
19	export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
20	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
21	  return { results };
22	};
